1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	interface Damage {
14	  itemType: string;
15	  amount: number;
16	}
17	
18	interface ClaimStep {
19	  op: "claim";
20	  policy: number;
21	  incident: { cause: string; damages: Damage[] };
22	}
23	
24	type Step = QuoteStep | ClaimStep;
25	
26	interface Scenario {
27	  customer: { yearsWithMHPCO: number };
28	  steps: Step[];
29	}
30	
31	interface Policy {
32	  items: Item[];
33	  remainingCap: number;
34	}
35	
36	type QuoteResult = { premium: number };
37	type ClaimResult = { payout: number; remainingCap: number };
38	type StepResult = QuoteResult | ClaimResult;
39	
40	const BASE_PREMIUM: Record<string, number> = {
41	  sword: 100,
42	  amulet: 60,
43	  staff: 80,
44	  potion: 40,
45	  rune: 25,
46	};
47	
48	const INSURANCE_VALUE: Record<string, number> = {
49	  sword: 1000,
50	  amulet: 600,
51	  staff: 800,
52	  potion: 400,
53	  rune: 250,
54	  moonstone: 250,
55	};
56	
57	const DEDUCTIBLE = 100;
58	const CAP_MULTIPLIER = 2;
59	const HIGH_DAMAGE_ENCH_THRESHOLD = 8;
60	const HIGH_DAMAGE_REIMBURSE_RATE = 0.5;
61	
62	const FIRST_INSURANCE_RATE = 0.1;
63	const CURSE_RATE = 0.5;
64	const HIGH_ENCH_RATE = 0.3;
65	const HIGH_ENCH_THRESHOLD = 5;
66	const LOYALTY_RATE = 0.2;
67	const LOYALTY_THRESHOLD = 2;
68	const FOLLOWUP_RATE = 0.15;
69	const PROCESSING_FEE = 5;
70	
71	const COMPONENT_PREMIUM = 25;
72	const BLOCK_SIZE = 3;
73	const BLOCK_PREMIUM = 60;
74	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
75	const KNOWN_ITEM_TYPES = new Set([...Object.keys(BASE_PREMIUM), ...COMPONENT_TYPES]);
76	
77	const validateQuoteItems = (items: Item[]): void => {
78	  for (const item of items) {
79	    if (!KNOWN_ITEM_TYPES.has(item.type)) {
80	      throw new Error(`Unknown item type: ${item.type}`);
81	    }
82	  }
83	};
84	
85	const componentBasePremium = (count: number): number =>
86	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
87	
88	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
89	
90	const isMainItem = (item: Item): boolean => !isComponent(item);
91	
92	const countValues = (values: string[]): Map<string, number> =>
93	  values.reduce(
94	    (counts, value) => counts.set(value, (counts.get(value) ?? 0) + 1),
95	    new Map<string, number>(),
96	  );
97	
98	const countByType = (items: Item[]): Map<string, number> =>
99	  countValues(items.map((item) => item.type));
100	
101	const componentTotal = (items: Item[]): number =>
102	  [...countByType(items.filter(isComponent)).values()].reduce(
103	    (sum, count) => sum + componentBasePremium(count),
104	    0,
105	  );
106	
107	const basePremium = (items: Item[]): number => {
108	  const mainTotal = items
109	    .filter(isMainItem)
110	    .reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
111	  return mainTotal + componentTotal(items);
112	};
113	
114	const mainItemBase = (item: Item): number => BASE_PREMIUM[item.type];
115	
116	const surchargeFor = (
117	  items: Item[],
118	  qualifies: (item: Item) => boolean,
119	  rate: number,
120	): number =>
121	  items
122	    .filter((item) => isMainItem(item) && qualifies(item))
123	    .reduce((sum, item) => sum + mainItemBase(item) * rate, 0);
124	
125	const isCursed = (item: Item): boolean => item.cursed === true;
126	
127	const curseSurcharge = (items: Item[]): number =>
128	  surchargeFor(items, isCursed, CURSE_RATE);
129	
130	const isHighlyEnchanted = (item: Item): boolean =>
131	  (item.enchantment ?? 0) >= HIGH_ENCH_THRESHOLD;
132	
133	const highEnchantmentSurcharge = (items: Item[]): number =>
134	  surchargeFor(items, isHighlyEnchanted, HIGH_ENCH_RATE);
135	
136	const discountWhen = (policyBase: number, qualifies: boolean, rate: number): number =>
137	  qualifies ? policyBase * rate : 0;
138	
139	const isLoyal = (years: number): boolean => years >= LOYALTY_THRESHOLD;
140	
141	const quotePremium = (items: Item[], years: number, isFollowUp: boolean): number => {
142	  const policyBase = basePremium(items);
143	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
144	  const itemSurcharges = curseSurcharge(items) + highEnchantmentSurcharge(items);
145	  const loyalty = discountWhen(policyBase, isLoyal(years), LOYALTY_RATE);
146	  const followUp = discountWhen(policyBase, isFollowUp, FOLLOWUP_RATE);
147	  return Math.ceil(
148	    policyBase + itemSurcharges + firstInsurance - loyalty - followUp + PROCESSING_FEE,
149	  );
150	};
151	
152	const insuranceSum = (items: Item[]): number =>
153	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
154	
155	const reimbursableAmount = (amount: number, item: Item | undefined): number => {
156	  if ((item?.enchantment ?? 0) >= HIGH_DAMAGE_ENCH_THRESHOLD) {
157	    return amount * HIGH_DAMAGE_REIMBURSE_RATE;
158	  }
159	  return amount;
160	};
161	
162	const damagePayout = (damage: Damage, item: Item | undefined): number =>
163	  Math.max(reimbursableAmount(damage.amount, item) - DEDUCTIBLE, 0);
164	
165	const openPolicy = (items: Item[]): Policy => ({
166	  items,
167	  remainingCap: insuranceSum(items) * CAP_MULTIPLIER,
168	});
169	
170	const insuredItem = (policy: Policy, itemType: string): Item | undefined =>
171	  policy.items.find((item) => item.type === itemType);
172	
173	const desiredPayout = (policy: Policy, damages: Damage[]): number =>
174	  Math.floor(
175	    damages.reduce(
176	      (sum, damage) => sum + damagePayout(damage, insuredItem(policy, damage.itemType)),
177	      0,
178	    ),
179	  );
180	
181	const validateDamageCounts = (policy: Policy, damages: Damage[]): void => {
182	  const insuredCounts = countByType(policy.items);
183	  const damageCounts = countValues(damages.map((damage) => damage.itemType));
184	  for (const [type, count] of damageCounts) {
185	    if (count > (insuredCounts.get(type) ?? 0)) {
186	      throw new Error(`Claim references more ${type} than insured`);
187	    }
188	  }
189	};
190	
191	const validateDamageAmounts = (damages: Damage[]): void => {
192	  if (damages.some((damage) => damage.amount < 0)) {
193	    throw new Error("Negative damage amount");
194	  }
195	};
196	
197	const validateClaim = (policy: Policy, damages: Damage[]): void => {
198	  validateDamageAmounts(damages);
199	  validateDamageCounts(policy, damages);
200	};
201	
202	const processClaim = (policy: Policy, claim: ClaimStep): ClaimResult => {
203	  const { damages } = claim.incident;
204	  validateClaim(policy, damages);
205	  const payout = Math.min(desiredPayout(policy, damages), policy.remainingCap);
206	  policy.remainingCap -= payout;
207	  return { payout, remainingCap: policy.remainingCap };
208	};
209	
210	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
211	  const years = scenario.customer.yearsWithMHPCO;
212	  const policies: Policy[] = [];
213	  let quoteCount = 0;
214	  const results = scenario.steps.map((step, index): StepResult => {
215	    if (step.op === "quote") {
216	      validateQuoteItems(step.items);
217	      const isFollowUp = quoteCount > 0;
218	      quoteCount += 1;
219	      policies[index] = openPolicy(step.items);
220	      return { premium: quotePremium(step.items, years, isFollowUp) };
221	    }
222	    return processClaim(policies[step.policy], step);
223	  });
224	  return { results };
225	};
