1	import { readFileSync } from "node:fs";
2	import { runScenario } from "./claim-office.js";
3	
4	try {
5	  const input = readFileSync(0, "utf8");
6	  const scenario = JSON.parse(input);
7	  const result = runScenario(scenario);
8	  process.stdout.write(JSON.stringify(result));
9	} catch (error) {
10	  process.stderr.write(error instanceof Error ? error.message : String(error));
11	  process.exit(1);
12	}
